{"content": "   501|// ─── Hono App ─────────────────────────────────────────────────────
   502|const app = new Hono();
   503|
   504|const snap: SnapFunction = async (ctx) => {
   505|  const base = baseUrl(ctx.request);
   506|
   507|  // ── GET: Gate page ──
   508|  if (ctx.action.type === "get") {
   509|    return gatePage(base);
   510|  }
   511|
   512|  // ── POST: Handle actions ──
   513|  const fid = ctx.action.user.fid;
   514|  const url = new URL(ctx.request.url);
   515|  const action = url.searchParams.get("action") ?? "";
   516|  const targetFidStr = url.searchParams.get("tid");
   517|
   518|  // ── Gate: Pass button ──
   519|  if (action === "gate_pass") {
   520|    await setBehavioralTag(fid, "cautious");
   521|    return await handleGateAction(fid, base);
   522|  }
   523|
   524|  // ── Gate: Yass button ──
   525|  if (action === "gate_yass") {
   526|    await setBehavioralTag(fid, "adventurous");
   527|    return await handleGateAction(fid, base);
   528|  }
   529|
   530|  // ── Swipe: Pass ──
   531|  if (action === "swipe_pass" && targetFidStr) {
   532|    return await handleSwipe(fid, parseInt(targetFidStr), "pass", base);
   533|  }
   534|
   535|  // ── Swipe: Yass ──
   536|  if (action === "swipe_yass" && targetFidStr) {
   537|    return await handleSwipe(fid, parseInt(targetFidStr), "yass", base);
   538|  }
   539|
   540|  // Fallback
   541|  return gatePage(base);
   542|};
   543|
   544|// ─── Gate Action Handler ──────────────────────────────────────────
   545|async function handleGateAction(fid: number, base: string) {
   546|  // Check if already qualified
   547|  const existingQual = await getQualification(fid);
   548|  if (existingQual?.qualified) {
   549|    return await showNextProfile(fid, base);
   550|  }
   551|
   552|  // Run qualification (free tier)
   553|  const user = await fetchUser(fid);
   554|  if (!user) {
   555|    return rejectionPage();
   556|  }
   557|
   558|  const qual = qualifyUser(user);
   559|  await setQualification(fid, qual);
   560|
   561|  if (!qual.qualified) {
   562|    return rejectionPage();
   563|  }
   564|
   565|  // Qualified — show first profile
   566|  return await showNextProfile(fid, base);
   567|}
   568|
   569|// ─── Swipe Handler ────────────────────────────────────────────────
   570|async function handleSwipe(
   571|  swiperFid: number,
   572|  targetFid: number,
   573|  direction: string,
   574|  base: string
   575|) {
   576|  // Check daily limit
   577|  const count = await getSwipeCount(swiperFid);
   578|  if (count >= DAILY_SWIPE_LIMIT) {
   579|    return dailyLimitPage();
   580|  }
   581|
   582|  // Record swipe
   583|  const tag = (await getBehavioralTag(swiperFid)) ?? "unknown";
   584|  await recordSwipe(swiperFid, targetFid, direction, tag);
   585|  await incrementSwipe(swiperFid);
   586|
   587|  // Show next profile
   588|  return await showNextProfile(swiperFid, base);
   589|}
   590|
   591|// ─── Show Next Profile ────────────────────────────────────────────
   592|async function showNextProfile(fid: number, base: string) {
   593|  // Check daily limit
   594|  const count = await getSwipeCount(fid);
   595|  if (count >= DAILY_SWIPE_LIMIT) {
   596|    return dailyLimitPage();
   597|  }
   598|
   599|  // Get remaining pool
   600|  let pool = await getProfilePool(fid);
   601|  const swiped = await getSwipedFids(fid);
   602|
   603|  // Filter out already swiped
   604|  pool = pool.filter((p) => !swiped.has(p.fid));
   605|
   606|  // If pool is low, rebuild
   607|  if (pool.length < 3) {
   608|    const newProfiles = await buildProfilePool(fid);
   609|    const existingFids = new Set(pool.map((p) => p.fid));
   610|    for (const p of newProfiles) {
   611|      if (!existingFids.has(p.fid) && !swiped.has(p.fid)) {
   612|        pool.push(p);
   613|        existingFids.add(p.fid);
   614|      }
   615|    }
   616|    await setProfilePool(fid, pool);
   617|  }
   618|
   619|  if (pool.length === 0) {
   620|    return noMorePage();
   621|  }
   622|
   623|  // Take the first profile
   624|  const next = pool[0];
   625|  await setProfilePool(fid, pool.slice(1));
   626|
   627|  const remaining = DAILY_SWIPE_LIMIT - count;
   628|  return profilePage(next, remaining, base);
   629|}
